// marshalTypesAssistantToAssistantResponseBody builds a value of type
// *AssistantResponseBody from a value of type *types.Assistant.
func marshalTypesAssistantToAssistantResponseBody(v *types.Assistant) *AssistantResponseBody {
	res := &AssistantResponseBody{
		ID:             v.ID,
		ProjectID:      v.ProjectID,
		Name:           v.Name,
		Model:          v.Model,
		Instructions:   v.Instructions,
		WarmTTLSeconds: v.WarmTTLSeconds,
		MaxConcurrency: v.MaxConcurrency,
		Status:         v.Status,
		CreatedAt:      v.CreatedAt,
		UpdatedAt:      v.UpdatedAt,
	}
	if v.Toolsets != nil {
		res.Toolsets = make([]*AssistantToolsetRefResponseBody, len(v.Toolsets))
		for i, val := range v.Toolsets {
			if val == nil {
				res.Toolsets[i] = nil
				continue
			}
			res.Toolsets[i] = marshalTypesAssistantToolsetRefToAssistantToolsetRefResponseBody(val)
		}
	} else {
		res.Toolsets = []*AssistantToolsetRefResponseBody{}
	}

	return res
}

// marshalTypesAssistantToolsetRefToAssistantToolsetRefResponseBody builds a
// value of type *AssistantToolsetRefResponseBody from a value of type
// *types.AssistantToolsetRef.
func marshalTypesAssistantToolsetRefToAssistantToolsetRefResponseBody(v *types.AssistantToolsetRef) *AssistantToolsetRefResponseBody {
	res := &AssistantToolsetRefResponseBody{
		ToolsetSlug:     v.ToolsetSlug,
		EnvironmentSlug: v.EnvironmentSlug,
	}

	return res
}

// unmarshalAssistantToolsetRefRequestBodyToTypesAssistantToolsetRef builds a
// value of type *types.AssistantToolsetRef from a value of type
// *AssistantToolsetRefRequestBody.
func unmarshalAssistantToolsetRefRequestBodyToTypesAssistantToolsetRef(v *AssistantToolsetRefRequestBody) *types.AssistantToolsetRef {
	res := &types.AssistantToolsetRef{
		ToolsetSlug:     *v.ToolsetSlug,
		EnvironmentSlug: v.EnvironmentSlug,
	}

	return res
}
